import{_ as a,o as n,c as e,a as i}from"./chunks/framework.BHSVNLI7.js";const u=JSON.parse('{"title":"WSL2 环境摸底与交叉编译工具链","description":"","frontmatter":{"title":"WSL2 环境摸底与交叉编译工具链","prerequisites":[],"next":["kernel-mini-config"],"difficulty":"beginner","tags":["wsl2","cross-compile","toolchain","arm64"],"architectures":["arm64"],"kernel_version":"6.19"},"headers":[],"relativePath":"tutorials/foundations/wsl2-env-toolchain.md","filePath":"tutorials/foundations/wsl2-env-toolchain.md","lastUpdated":null}'),l={name:"tutorials/foundations/wsl2-env-toolchain.md"};function p(r,s,t,c,h,d){return n(),e("div",null,[...s[0]||(s[0]=[i(`<h2 id="welcome-kernel" tabindex="-1">Welcome Kernel！ <a class="header-anchor" href="#welcome-kernel" aria-label="Permalink to &quot;Welcome Kernel！&quot;">​</a></h2><p>这是注定一场极端漫长的路程，Linux作为一个演化了几十年的操作系统，复杂度可以堪称人类历史上软件工程的顶峰了！千里之行始于足下。我们就从这一篇文章开始我们的路途！</p><h2 id="做什么" tabindex="-1">做什么 <a class="header-anchor" href="#做什么" aria-label="Permalink to &quot;做什么&quot;">​</a></h2><p>笔者是在WSL2上开始这套基于自己学习路程的部分开发的教程，所以，其他真实物理机的发行版，可能也许需要一定的修改。笔者的WSL2上跑的发行版是Arch Linux。只是用的习惯了！所以请原谅，如果你是Ubuntu/Debain系的朋友可能需要调整一下指令！</p><p>我们要在 WSL2 里搭建一套完整的 Linux 内核开发环境。具体来说，我们需要确认 WSL2 能不能胜任这项工作，然后安装交叉编译工具链，为后续编译 ARM64 内核做好准备。完成这篇之后，我们会有一个&quot;确认可用&quot;的开发环境，工具链就位，随时可以开始配内核、编译、跑 QEMU。</p><h2 id="要了解什么" tabindex="-1">要了解什么 <a class="header-anchor" href="#要了解什么" aria-label="Permalink to &quot;要了解什么&quot;">​</a></h2><h3 id="为什么选-wsl2" tabindex="-1">为什么选 WSL2 <a class="header-anchor" href="#为什么选-wsl2" aria-label="Permalink to &quot;为什么选 WSL2&quot;">​</a></h3><p>我们得先回答一个问题：为什么不直接在物理机上搞内核开发？答案很简单——我们编译出来的 ARM64 内核根本没法在 x86 宿主机上跑，它必须在一个模拟器（QEMU）里面执行。WSL2 提供了一个完整的 Linux 环境，同时又是 Windows 的一个轻量级虚拟机，这让我们既能享受 Linux 工具链的便利，又不用担心搞崩宿主系统——因为真正运行我们编译出来的内核的是 QEMU，它被完全隔离在 WSL2 之内。就算内核写炸了、驱动崩了、rootfs 搞烂了，最坏的结果不过是 QEMU 进程挂掉，宿主机纹丝不动。</p><h3 id="摸清-wsl2-的能力" tabindex="-1">摸清 WSL2 的能力 <a class="header-anchor" href="#摸清-wsl2-的能力" aria-label="Permalink to &quot;摸清 WSL2 的能力&quot;">​</a></h3><p>在动手装任何东西之前，我们先花几分钟搞清楚手上这台机器到底是什么水平。先看内核版本和基本系统信息：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uname</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Linux Charliechen 6.6.87.2-microsoft-standard-WSL2 #1 SMP PREEMPT_DYNAMIC ... x86_64 GNU/Linux</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>注意那个 <code>-microsoft-standard-WSL2</code> 后缀——这就是 WSL2 自带的 Linux 内核，跟我们后续要编译的 ARM64 内核完全是两回事。这个内核只是我们的&quot;宿主系统&quot;，真正要学习和折腾的目标内核将在 QEMU 里运行。</p><p>接着看一下 CPU 和虚拟化能力：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/cpuinfo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -20</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># processor    : 0</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># model name   : AMD Ryzen 7 5800H with Radeon Graphics</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># cpu cores    : 7</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这里有一个关键检查项——<code>/dev/kvm</code> 是否存在。KVM（Kernel-based Virtual Machine）是 Linux 内核自带的虚拟化加速器，如果 WSL2 支持 KVM，QEMU 就能用硬件虚拟化大幅提升运行速度；如果不存在，QEMU 也能跑，只是纯软件模拟，会慢不少。从 Windows 11 22H2 开始，WSL2 开始支持嵌套虚拟化，<code>/dev/kvm</code> 有很大概率是存在的：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/kvm</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /dev/kvm  ← 存在，QEMU 可以用硬件加速</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>我们这台机器的底子相当不错——AMD Ryzen 7 5800H，7 核 14 线程，KVM 可用，编译内核的并行度 (<code>-j14</code>) 完全拉得开。</p><p>再看看发行版信息，因为这直接影响包管理命令：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/os-release</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># NAME=&quot;Arch Linux&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># PRETTY_NAME=&quot;Arch Linux&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ID=arch</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>我们用的是 Arch Linux（rolling release），包管理器是 <code>pacman</code> 而不是 <code>apt</code>。如果你用的是 Ubuntu/Debian 系的 WSL2，后面安装软件的命令会不一样，我会在对应位置标注两种写法。</p><h3 id="交叉编译工具链-在-x86-上造-arm-的轮子" tabindex="-1">交叉编译工具链：在 x86 上造 ARM 的轮子 <a class="header-anchor" href="#交叉编译工具链-在-x86-上造-arm-的轮子" aria-label="Permalink to &quot;交叉编译工具链：在 x86 上造 ARM 的轮子&quot;">​</a></h3><p>接下来我们装交叉编译工具链。为什么叫&quot;交叉&quot;编译？因为我们的宿主机是 x86_64 架构，但目标平台是 ARM64——编译器跑在 x86 上，但它生成的机器码是给 ARM 执行的。这就像你在一个国家的工厂里生产另一个国家标准的产品，工具本身得做适配。</p><p>安装工具链本身很简单，一行命令的事：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Arch Linux</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aarch64-linux-gnu-gcc</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # ARM64 交叉编译器</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ubuntu / Debian</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gcc-aarch64-linux-gnu</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # ARM64 交叉编译器</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>装完之后验证一下：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aarch64-linux-gnu-gcc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># aarch64-linux-gnu-gcc (GCC) 15.2.0</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Copyright (C) 2025 Free Software Foundation, Inc.</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>看到版本号就说明工具链就位了。现在我们来理解一下这个看起来很长的名字到底在说什么——<code>aarch64-linux-gnu-gcc</code> 的命名规则是 <code>&lt;架构&gt;-&lt;厂商&gt;-&lt;操作系统&gt;-&lt;ABI&gt;-&lt;工具&gt;</code>，其中 <code>aarch64</code> 是 ARM64 的官方架构名称（ARM 公司定义的），<code>linux</code> 表示目标系统是 Linux，<code>gnu</code> 表示使用 GNU C 库（glibc），最后的 <code>gcc</code> 就是我们熟悉的 C 编译器。这套命名规则在整个交叉编译工具链里是一致的，比如 <code>aarch64-linux-gnu-ld</code> 是链接器，<code>aarch64-linux-gnu-objdump</code> 是反汇编器，<code>aarch64-linux-gnu-gdb</code> 是调试器——它们共享同一个前缀。</p><h3 id="arch-和-cross-compile-内核构建系统的两个关键变量" tabindex="-1">ARCH 和 CROSS_COMPILE：内核构建系统的两个关键变量 <a class="header-anchor" href="#arch-和-cross-compile-内核构建系统的两个关键变量" aria-label="Permalink to &quot;ARCH 和 CROSS_COMPILE：内核构建系统的两个关键变量&quot;">​</a></h3><p>内核的构建系统（Kbuild）通过两个环境变量来控制交叉编译：<code>ARCH</code> 指定目标架构，<code>CROSS_COMPILE</code> 指定工具链前缀。</p><p>关于这个事情，笔者建议，Linux Documentation是任何一个学习内核的朋友要开始熟悉的。笔者很乐意从Documentation上摘抄内容，毕竟文档站的权威性总是远远大于自己找LLM胡言乱语瞎编乱造，对不对？</p><blockquote><p>URL: <a href="https://www.kernel.org/doc/html/latest/kbuild/kbuild.html" target="_blank" rel="noreferrer">https://www.kernel.org/doc/html/latest/kbuild/kbuild.html</a></p></blockquote><p>找到ARCH和CROSS_COMPILE的介绍。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ARCH</span></span>
<span class="line"><span>Set ARCH to the architecture to be built.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>In most cases the name of the architecture is the same as the directory name found in the arch/ directory.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>But some architectures such as x86 and sparc have aliases.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>x86: i386 for 32 bit, x86_64 for 64 bit</span></span>
<span class="line"><span></span></span>
<span class="line"><span>parisc: parisc64 for 64 bit</span></span>
<span class="line"><span></span></span>
<span class="line"><span>sparc: sparc32 for 32 bit, sparc64 for 64 bit</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CROSS_COMPILE</span></span>
<span class="line"><span>Specify an optional fixed part of the binutils filename. CROSS_COMPILE can be a part of the filename or the full path.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CROSS_COMPILE is also used for ccache in some setups.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>嗯？英文你看不懂？没关系。翻译软件请经常开，笔者这次帮你代劳一下：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ARCH</span></span>
<span class="line"><span>将 ARCH 设置为要构建的架构。在大多数情况下，架构名称与 arch/ 目录中的目录名称相同。但某些架构如 x86 和 sparc 有别名。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- x86：32 位使用 i386，64 位使用 x86_64</span></span>
<span class="line"><span>- parisc：64 位使用 parisc64</span></span>
<span class="line"><span>- sparc：32 位使用 sparc32，64 位使用 sparc64</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CROSS_COMPILE</span></span>
<span class="line"><span>- 指定 binutils 文件名的可选固定部分。CROSS_COMPILE 可以是文件名的一部分或完整路径。在某些设置中，CROSS_COMPILE 也用于 ccache。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>这里有一个很容易踩的坑——<code>ARCH</code> 的值和工具链前缀的命名并不总是一一对应。对于 ARM64 来说，内核构建系统用的架构名是 <code>arm64</code>，但工具链前缀是 <code>aarch64-linux-gnu-</code>，两者不一样。这是历史原因造成的，ARM64 架构在内核社区一直叫 <code>arm64</code>，而工具链这边用的是 ARM 官方定义的 <code>aarch64</code> 名称。项目的 <a href="./scripts/linux-action-scripts.sh">linux-action-scripts.sh</a> 第 69-72 行专门做了这个映射，把用户传入的 <code>aarch64</code> 或 <code>arm64</code> 统一转成 Kbuild 认的 <code>arm64</code>。</p><p><code>CROSS_COMPILE</code> 更有意思——它不是一个完整的命令名，而是一个前缀。内核构建系统会自动在这个前缀后面拼接 <code>gcc</code>、<code>ld</code>、<code>objcopy</code> 等后缀来找到对应的工具。也就是说，当你设置 <code>CROSS_COMPILE=aarch64-linux-gnu-</code> 时，make 会去找 <code>aarch64-linux-gnu-gcc</code>、<code>aarch64-linux-gnu-ld</code>、<code>aarch64-linux-gnu-objcopy</code> 等一系列工具。如果 <code>CROSS_COMPILE</code> 是空字符串，make 就直接用本机的 <code>gcc</code>、<code>ld</code> 等——这就是为什么忘记设这个变量的时候，内核会编译成 x86 架构的，因为这个空字符串前缀导致构建系统用了宿主机的编译器。</p><p>一个推荐的做法是把这两个变量 export 到当前 shell 里，这样后面所有 make 命令都不用重复写了：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ARCH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">arm64</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CROSS_COMPILE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">aarch64-linux-gnu-</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>除了工具链之外，编译内核还需要一些辅助工具（bison、flex 等）。Ubuntu/Debian 下一行搞定：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ubuntu / Debian, UnAuthorized Commands，这部分我没验证</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build-essential</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libncurses-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bison</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libssl-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libelf-dev</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Arch Linux 用户一般这些工具已经通过 base-devel 组装好了，如果没有就 <code>pacman -S base-devel</code> 补齐。</p><h2 id="动手试试" tabindex="-1">动手试试 <a class="header-anchor" href="#动手试试" aria-label="Permalink to &quot;动手试试&quot;">​</a></h2><p>笔者是这样玩的！您也一起来试试吧！</p><ol><li>在你的 WSL2 终端里依次运行 <code>uname -r</code>、<code>cat /proc/version</code>、<code>ls /dev/kvm</code>，记录你的环境信息</li><li>安装 ARM64 交叉编译器并验证 <code>aarch64-linux-gnu-gcc --version</code> 能输出版本号</li><li>在终端里 export <code>ARCH=arm64</code> 和 <code>CROSS_COMPILE=aarch64-linux-gnu-</code>，然后运行 <code>echo $ARCH</code> 和 <code>echo $CROSS_COMPILE</code> 确认变量已生效</li><li>如果你对 RISC-V 也感兴趣，可以顺便装 <code>gcc-riscv64-linux-gnu</code>（Arch: <code>pacman -S riscv64-linux-gnu-gcc</code>），后续的练习会支持多架构</li></ol><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://www.kernel.org/doc/html/latest/kbuild/kbuild.html" target="_blank" rel="noreferrer">Kbuild 内核构建系统文档</a> — kernel.org 对 <code>ARCH</code>、<code>CROSS_COMPILE</code> 等变量的官方定义</li><li><a href="https://docs.kernel.org/admin-guide/README.html" target="_blank" rel="noreferrer">Linux 内核构建说明</a> — 内核源码根目录 README 的网页版</li><li><a href="https://jensd.be/1126/linux/cross-compiling-for-arm-or-aarch64-on-debian-or-ubuntu" target="_blank" rel="noreferrer">交叉编译 Debian/Ubuntu 实战</a> — Ubuntu 系环境下的交叉编译教程</li></ul>`,47)])])}const b=a(l,[["render",p]]);export{u as __pageData,b as default};
